{"call_id":"call_M2EVb5diCWh8GKOkrhgZel2v","turn_id":"019db4f7-e059-7e80-9cec-63cf3bea0c7f","command":["C:\Program Files\PowerShell\7\pwsh.exe","-Command","Get-Content -Path 'src/WinSentinel.Cli/ConsoleFormatter.Pulse.cs' -TotalCount 260"],"cwd":"C:\Users\onlin\.openclaw\workspace\temp-builder","parsed_cmd":[{"type":"unknown","cmd":"Get-Content -Path 'src/WinSentinel.Cli/ConsoleFormatter.Pulse.cs' -TotalCount 260"}],"source":"agent","stdout":"namespace WinSentinel.Cli;

public static partial class ConsoleFormatter
{
    public static void PrintPulse(
        List<(DateTimeOffset date, int score, int total, int critical, int high, int medium, int low)> dataPoints,
        int chartWidth,
        int alertBelow,
        bool showFindings)
    {
        Console.WriteLine();
        Console.ForegroundColor = ConsoleColor.Cyan;
        Console.WriteLine("  ╔══════════════════════════════════════════════╗");
        Console.WriteLine("  ║       💓  Security Pulse                    ║");
        Console.WriteLine("  ╚══════════════════════════════════════════════╝");
        Console.ResetColor();

        if (dataPoints.Count == 0)
        {
            Console.ForegroundColor = ConsoleColor.Yellow;
            Console.WriteLine("  No audit data found.");
            Console.ResetColor();
            return;
        }

        var first = dataPoints[0];
        var last = dataPoints[^1];
        var scores = dataPoints.Select(p => p.score).ToList();
        var avg = scores.Average();
        var min = scores.Min();
        var max = scores.Max();
        var current = last.score;
        var delta = current - first.score;
        var alertCount = scores.Count(s => s < alertBelow);

        // Volatility (standard deviation)
        var variance = scores.Select(s => Math.Pow(s - avg, 2)).Average();
        var stdDev = Math.Sqrt(variance);

        // Streak detection
        int streak = 0;
        bool streakUp = true;
