            var findRunIdParam = findCmd.Parameters.Add("@runId", Microsoft.Data.Sqlite.SqliteType.Integer);
            var findModuleParam = findCmd.Parameters.Add("@module", Microsoft.Data.Sqlite.SqliteType.Text);
