            var findRemediationParam = findCmd.Parameters.Add("@remediation", Microsoft.Data.Sqlite.SqliteType.Text);
            findCmd.Prepare();

            foreach (var result in report.Results)
            {
                modRunIdParam.Value = runId;
                modNameParam.Value = result.ModuleName;
